$(document).ready(function(){var t=$(".header__right"),s=$(".header__menu-toggle"),e=$(".header__menu-close"),n=$(".header__mask");s.on("click",function(e){e.preventDefault(),t.toggleClass("is-menu-opened"),n.toggleClass("is-active")}),e.on("click",function(e){e.preventDefault(),t.removeClass("is-menu-opened"),n.removeClass("is-active")}),$(document).on("click touchstart",function(e){0==$(e.target).closest(t).length&&0==$(e.target).closest(s).length&&(t.removeClass("is-menu-opened"),n.removeClass("is-active"))}),$(".gallery").slick()});